{"code":0,"message":{"totalFound":982,"page":5,"pageSize":200,"docFrom":800,"docList":[{"number":801,"docInfo":{"docId":"11129860","docFilename":"ChunQiu_00063","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯閔公二年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"387\" RefId=\"魯閔公二年正月\" Term=\"魯閔公二年正月\"><\/AlignBegin>二年春，王正月，齊人遷陽。<AlignEnd Key=\"387\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"388\" RefId=\"魯閔公二年五月\" Term=\"魯閔公二年五月\"><\/AlignBegin>夏，五月，乙酉，吉禘于莊公。<AlignEnd Key=\"388\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"389\" RefId=\"魯閔公二年八月\" Term=\"魯閔公二年八月\"><\/AlignBegin>秋，八月，辛丑，公薨。<AlignEnd Key=\"389\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"390\" RefId=\"魯閔公二年九月\" Term=\"魯閔公二年九月\"><\/AlignBegin>九月，夫人姜氏孫于邾。<AlignEnd Key=\"390\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"391\" RefId=\"魯閔公二年九月\" Term=\"魯閔公二年九月\"><\/AlignBegin>公子慶父出奔莒。<AlignEnd Key=\"391\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"392\" RefId=\"魯閔公二年十月\" Term=\"魯閔公二年十月\"><\/AlignBegin>冬，齊高子來盟。<AlignEnd Key=\"392\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"393\" RefId=\"魯閔公二年十二月\" Term=\"魯閔公二年十二月\"><\/AlignBegin>十有二月，狄入衛。<AlignEnd Key=\"393\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"394\" RefId=\"魯閔公二年十二月\" Term=\"魯閔公二年十二月\"><\/AlignBegin>鄭棄其師。<AlignEnd Key=\"394\"><\/AlignEnd>\n<\/Content>"}},{"number":802,"docInfo":{"docId":"11129861","docFilename":"ChunQiu_00064","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公元年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"395\" RefId=\"魯僖公元年正月\" Term=\"魯僖公元年正月\"><\/AlignBegin>元年春，王正月。<AlignEnd Key=\"395\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"396\" RefId=\"魯僖公元年正月\" Term=\"魯僖公元年正月\"><\/AlignBegin>齊師、宋師、曹伯次于聶北，救邢。<AlignEnd Key=\"396\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"397\" RefId=\"魯僖公元年六月\" Term=\"魯僖公元年六月\"><\/AlignBegin>夏，六月。邢遷于夷儀<AlignEnd Key=\"397\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"398\" RefId=\"魯僖公元年六月\" Term=\"魯僖公元年六月\"><\/AlignBegin>齊師、宋師、曹師城邢。<AlignEnd Key=\"398\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"399\" RefId=\"魯僖公元年七月\" Term=\"魯僖公元年七月\"><\/AlignBegin>秋，七月，戊辰。夫人姜氏薨于夷，齊人以歸。<AlignEnd Key=\"399\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"400\" RefId=\"魯僖公元年七月\" Term=\"魯僖公元年七月\"><\/AlignBegin>楚人伐鄭。<AlignEnd Key=\"400\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"401\" RefId=\"魯僖公元年八月\" Term=\"魯僖公元年八月\"><\/AlignBegin>八月。公會齊侯、宋公、鄭伯、曹伯、邾人于檉。<AlignEnd Key=\"401\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"402\" RefId=\"魯僖公元年九月\" Term=\"魯僖公元年九月\"><\/AlignBegin>九月。公敗邾師于偃。<AlignEnd Key=\"402\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"403\" RefId=\"魯僖公元年十月\" Term=\"魯僖公元年十月\"><\/AlignBegin>冬，十月，壬午。公子友帥師敗莒師于酈，獲莒拏。<AlignEnd Key=\"403\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"404\" RefId=\"魯僖公元年十二月\" Term=\"魯僖公元年十二月\"><\/AlignBegin>十有二月，丁已。夫人氏之喪至自齊。<AlignEnd Key=\"404\"><\/AlignEnd>\n<\/Content>"}},{"number":803,"docInfo":{"docId":"11129862","docFilename":"ChunQiu_00065","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公二年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"405\" RefId=\"魯僖公二年正月\" Term=\"魯僖公二年正月\"><\/AlignBegin>二年春，王正月。城楚丘。<AlignEnd Key=\"405\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"406\" RefId=\"魯僖公二年五月\" Term=\"魯僖公二年五月\"><\/AlignBegin>夏，五月，辛已。葬我小君哀姜。<AlignEnd Key=\"406\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"407\" RefId=\"魯僖公二年五月\" Term=\"魯僖公二年五月\"><\/AlignBegin>虞師、晉師滅下陽。<AlignEnd Key=\"407\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"408\" RefId=\"魯僖公二年九月\" Term=\"魯僖公二年九月\"><\/AlignBegin>秋，九月。齊侯、宋公、江人、黃人盟于貫。<AlignEnd Key=\"408\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"409\" RefId=\"魯僖公二年十月\" Term=\"魯僖公二年十月\"><\/AlignBegin>冬，十月。不雨。<AlignEnd Key=\"409\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"410\" RefId=\"魯僖公二年十月\" Term=\"魯僖公二年十月\"><\/AlignBegin>楚人侵鄭。<AlignEnd Key=\"410\"><\/AlignEnd>\n<\/Content>"}},{"number":804,"docInfo":{"docId":"11129863","docFilename":"ChunQiu_00066","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公三年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"411\" RefId=\"魯僖公三年正月\" Term=\"魯僖公三年正月\"><\/AlignBegin>三年春，王正月，不雨。<AlignEnd Key=\"411\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"412\" RefId=\"魯僖公三年四月\" Term=\"魯僖公三年四月\"><\/AlignBegin>夏，四月，不雨。<AlignEnd Key=\"412\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"413\" RefId=\"魯僖公三年四月\" Term=\"魯僖公三年四月\"><\/AlignBegin>徐人取舒。<AlignEnd Key=\"413\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"414\" RefId=\"魯僖公三年六月\" Term=\"魯僖公三年六月\"><\/AlignBegin>六月，雨。<AlignEnd Key=\"414\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"415\" RefId=\"魯僖公三年六月\" Term=\"魯僖公三年六月\"><\/AlignBegin>秋，齊侯、宋公、江人、黃人會于陽穀。<AlignEnd Key=\"415\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"416\" RefId=\"魯僖公三年六月\" Term=\"魯僖公三年六月\"><\/AlignBegin>冬，公子友如齊蒞盟。<AlignEnd Key=\"416\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"417\" RefId=\"魯僖公三年六月\" Term=\"魯僖公三年六月\"><\/AlignBegin>楚人伐鄭。<AlignEnd Key=\"417\"><\/AlignEnd>\n<\/Content>"}},{"number":805,"docInfo":{"docId":"11129864","docFilename":"ChunQiu_00067","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公四年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"418\" RefId=\"魯僖公四年正月\" Term=\"魯僖公四年正月\"><\/AlignBegin>四年春，王正月，公會齊侯、宋公、陳侯、衛侯、鄭伯、許男、曹伯侵蔡，蔡潰，遂伐楚，次于陘。<AlignEnd Key=\"418\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"419\" RefId=\"魯僖公四年四月\" Term=\"魯僖公四年四月\"><\/AlignBegin>夏，許男新臣卒。<AlignEnd Key=\"419\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"420\" RefId=\"魯僖公四年四月\" Term=\"魯僖公四年四月\"><\/AlignBegin>楚屈完來盟于師，盟于召陵。<AlignEnd Key=\"420\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"421\" RefId=\"魯僖公四年四月\" Term=\"魯僖公四年四月\"><\/AlignBegin>齊人執陳轅濤塗。<AlignEnd Key=\"421\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"422\" RefId=\"魯僖公四年七月\" Term=\"魯僖公四年七月\"><\/AlignBegin>秋，及江人、黃人伐陳。<AlignEnd Key=\"422\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"423\" RefId=\"魯僖公四年八月\" Term=\"魯僖公四年八月\"><\/AlignBegin>八月，公至自伐楚。<AlignEnd Key=\"423\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"424\" RefId=\"魯僖公四年八月\" Term=\"魯僖公四年八月\"><\/AlignBegin>葬許穆公。<AlignEnd Key=\"424\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"425\" RefId=\"魯僖公四年十二月\" Term=\"魯僖公四年十二月\"><\/AlignBegin>冬，十有二月，公孫茲帥師會齊人、宋人、衛人、鄭人、許人、曹人侵陳。<AlignEnd Key=\"425\"><\/AlignEnd>\n<\/Content>"}},{"number":806,"docInfo":{"docId":"11129865","docFilename":"ChunQiu_00068","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公五年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"426\" RefId=\"魯僖公五年正月\" Term=\"魯僖公五年正月\"><\/AlignBegin>五年春，晉侯殺其世子申生。<AlignEnd Key=\"426\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"427\" RefId=\"魯僖公五年正月\" Term=\"魯僖公五年正月\"><\/AlignBegin>杞伯姬來朝其子。<AlignEnd Key=\"427\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"428\" RefId=\"魯僖公五年四月\" Term=\"魯僖公五年四月\"><\/AlignBegin>夏，公孫茲如牟。<AlignEnd Key=\"428\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"429\" RefId=\"魯僖公五年四月\" Term=\"魯僖公五年四月\"><\/AlignBegin>公及齊侯、宋公、陳侯、衛侯、鄭伯、許男、曹伯，會王世子于首止。<AlignEnd Key=\"429\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"430\" RefId=\"魯僖公五年八月\" Term=\"魯僖公五年八月\"><\/AlignBegin>秋，八月，諸侯盟于首止，鄭伯逃歸，不盟<AlignEnd Key=\"430\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"431\" RefId=\"魯僖公五年八月\" Term=\"魯僖公五年八月\"><\/AlignBegin>楚人滅弦，弦子奔黃。<AlignEnd Key=\"431\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"432\" RefId=\"魯僖公五年九月\" Term=\"魯僖公五年九月\"><\/AlignBegin>九月，戊申朔，日有食之。<AlignEnd Key=\"432\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"433\" RefId=\"魯僖公五年十月\" Term=\"魯僖公五年十月\"><\/AlignBegin>冬，晉人執虞公。<AlignEnd Key=\"433\"><\/AlignEnd>\n<\/Content>"}},{"number":807,"docInfo":{"docId":"11129866","docFilename":"ChunQiu_00069","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公六年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"434\" RefId=\"魯僖公六年正月\" Term=\"魯僖公六年正月\"><\/AlignBegin>六年春，王正月。<AlignEnd Key=\"434\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"435\" RefId=\"魯僖公六年四月\" Term=\"魯僖公六年四月\"><\/AlignBegin>夏，公會齊侯、宋公、陳侯、衛侯、曹伯伐鄭，圍新城。<AlignEnd Key=\"435\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"436\" RefId=\"魯僖公六年七月\" Term=\"魯僖公六年七月\"><\/AlignBegin>秋，楚人圍許，諸侯遂救許<AlignEnd Key=\"436\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"437\" RefId=\"魯僖公六年十月\" Term=\"魯僖公六年十月\"><\/AlignBegin>冬，公至自伐鄭。<AlignEnd Key=\"437\"><\/AlignEnd>\n<\/Content>"}},{"number":808,"docInfo":{"docId":"11129867","docFilename":"ChunQiu_00070","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公七年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"438\" RefId=\"魯僖公七年正月\" Term=\"魯僖公七年正月\"><\/AlignBegin>七年春，齊人伐鄭。<AlignEnd Key=\"438\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"439\" RefId=\"魯僖公七年四月\" Term=\"魯僖公七年四月\"><\/AlignBegin>夏，小邾子來朝。<AlignEnd Key=\"439\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"440\" RefId=\"魯僖公七年四月\" Term=\"魯僖公七年四月\"><\/AlignBegin>鄭殺其大夫申侯。<AlignEnd Key=\"440\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"441\" RefId=\"魯僖公七年七月\" Term=\"魯僖公七年七月\"><\/AlignBegin>秋，七月，公會齊侯、宋公、陳世子款、鄭世子華，盟于甯母。<AlignEnd Key=\"441\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"442\" RefId=\"魯僖公七年七月\" Term=\"魯僖公七年七月\"><\/AlignBegin>曹伯班卒。<AlignEnd Key=\"442\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"443\" RefId=\"魯僖公七年七月\" Term=\"魯僖公七年七月\"><\/AlignBegin>公子友如齊。<AlignEnd Key=\"443\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"444\" RefId=\"魯僖公七年十月\" Term=\"魯僖公七年十月\"><\/AlignBegin>冬，葬曹昭公<AlignEnd Key=\"444\"><\/AlignEnd>\n<\/Content>"}},{"number":809,"docInfo":{"docId":"11129868","docFilename":"ChunQiu_00071","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公八年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"445\" RefId=\"魯僖公八年正月\" Term=\"魯僖公八年正月\"><\/AlignBegin>八年春，王正月，公會王人、齊侯、宋公、衛侯、許男、曹伯、陳世子款盟于洮，鄭伯乞盟。<AlignEnd Key=\"445\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"446\" RefId=\"魯僖公八年四月\" Term=\"魯僖公八年四月\"><\/AlignBegin>夏，狄伐晉。<AlignEnd Key=\"446\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"447\" RefId=\"魯僖公八年七月\" Term=\"魯僖公八年七月\"><\/AlignBegin>秋，七月，禘于大廟，用致夫人。<AlignEnd Key=\"447\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"448\" RefId=\"魯僖公八年十二月\" Term=\"魯僖公八年十二月\"><\/AlignBegin>冬，十有二月，丁未，天王崩。<AlignEnd Key=\"448\"><\/AlignEnd>\n<\/Content>"}},{"number":810,"docInfo":{"docId":"11129869","docFilename":"ChunQiu_00072","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公九年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"449\" RefId=\"魯僖公九年三月\" Term=\"魯僖公九年三月\"><\/AlignBegin>九年春，王三月，丁丑，宋公御說卒。<AlignEnd Key=\"449\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"450\" RefId=\"魯僖公九年四月\" Term=\"魯僖公九年四月\"><\/AlignBegin>夏，公會宰周公、齊侯、宋子、衛侯、鄭伯、許男、曹伯于葵丘。<AlignEnd Key=\"450\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"451\" RefId=\"魯僖公九年七月\" Term=\"魯僖公九年七月\"><\/AlignBegin>秋，七月，乙酉，伯姬卒。<AlignEnd Key=\"451\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"452\" RefId=\"魯僖公九年九月\" Term=\"魯僖公九年九月\"><\/AlignBegin>九月，戊辰，諸侯盟于葵丘。<AlignEnd Key=\"452\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"453\" RefId=\"魯僖公九年九月\" Term=\"魯僖公九年九月\"><\/AlignBegin>甲子，晉侯佹諸卒。<AlignEnd Key=\"453\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"454\" RefId=\"魯僖公九年十月\" Term=\"魯僖公九年十月\"><\/AlignBegin>冬，晉里奚克殺其君之子奚齊。<AlignEnd Key=\"454\"><\/AlignEnd>\n<\/Content>"}},{"number":811,"docInfo":{"docId":"11129870","docFilename":"ChunQiu_00073","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"455\" RefId=\"魯僖公十年正月\" Term=\"魯僖公十年正月\"><\/AlignBegin>十年春，王正月，公如齊。<AlignEnd Key=\"455\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"456\" RefId=\"魯僖公十年正月\" Term=\"魯僖公十年正月\"><\/AlignBegin>狄滅溫，溫子奔衛。<AlignEnd Key=\"456\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"457\" RefId=\"魯僖公十年正月\" Term=\"魯僖公十年正月\"><\/AlignBegin>晉里克弒其君卓，及其大夫荀息。<AlignEnd Key=\"457\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"458\" RefId=\"魯僖公十年四月\" Term=\"魯僖公十年四月\"><\/AlignBegin>夏，齊侯許男伐北戎。<AlignEnd Key=\"458\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"459\" RefId=\"魯僖公十年四月\" Term=\"魯僖公十年四月\"><\/AlignBegin>晉殺其大夫里克。<AlignEnd Key=\"459\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"460\" RefId=\"魯僖公十年七月\" Term=\"魯僖公十年七月\"><\/AlignBegin>秋，七月。<AlignEnd Key=\"460\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"461\" RefId=\"魯僖公十年十月\" Term=\"魯僖公十年十月\"><\/AlignBegin>冬，大雨雪。<AlignEnd Key=\"461\"><\/AlignEnd>\n<\/Content>"}},{"number":812,"docInfo":{"docId":"11129871","docFilename":"ChunQiu_00074","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十一年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"462\" RefId=\"魯僖公十一年正月\" Term=\"魯僖公十一年正月\"><\/AlignBegin>十有一年春，晉殺其大夫丕鄭父。<AlignEnd Key=\"462\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"463\" RefId=\"魯僖公十一年四月\" Term=\"魯僖公十一年四月\"><\/AlignBegin>夏，公及夫人姜氏，會齊侯于陽穀。<AlignEnd Key=\"463\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"464\" RefId=\"魯僖公十一年八月\" Term=\"魯僖公十一年八月\"><\/AlignBegin>秋，八月，大雩。<AlignEnd Key=\"464\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"465\" RefId=\"魯僖公十一年十月\" Term=\"魯僖公十一年十月\"><\/AlignBegin>冬，楚人伐黃。<AlignEnd Key=\"465\"><\/AlignEnd>\n<\/Content>"}},{"number":813,"docInfo":{"docId":"11129872","docFilename":"ChunQiu_00075","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十二年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"466\" RefId=\"魯僖公十二年三月\" Term=\"魯僖公十二年三月\"><\/AlignBegin>十有二年春，王三月，庚午，日有食之。<AlignEnd Key=\"466\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"467\" RefId=\"魯僖公十二年四月\" Term=\"魯僖公十二年四月\"><\/AlignBegin>夏，楚人滅黃。<AlignEnd Key=\"467\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"468\" RefId=\"魯僖公十二年七月\" Term=\"魯僖公十二年七月\"><\/AlignBegin>秋，七月。<AlignEnd Key=\"468\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"469\" RefId=\"魯僖公十二年十二月\" Term=\"魯僖公十二年十二月\"><\/AlignBegin>冬，十有二月，丁丑，陳侯杵臼卒。<AlignEnd Key=\"469\"><\/AlignEnd>\n<\/Content>"}},{"number":814,"docInfo":{"docId":"11129873","docFilename":"ChunQiu_00076","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十三年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"470\" RefId=\"魯僖公十三年正月\" Term=\"魯僖公十三年正月\"><\/AlignBegin>十有三年春，狄侵衛。<AlignEnd Key=\"470\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"471\" RefId=\"魯僖公十三年四月\" Term=\"魯僖公十三年四月\"><\/AlignBegin>夏，四月，葬陳宣公。<AlignEnd Key=\"471\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"472\" RefId=\"魯僖公十三年四月\" Term=\"魯僖公十三年四月\"><\/AlignBegin>公會齊侯、宋公、陳侯、衛侯、鄭伯、許男、曹伯于鹹。<AlignEnd Key=\"472\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"473\" RefId=\"魯僖公十三年九月\" Term=\"魯僖公十三年九月\"><\/AlignBegin>秋，九月，大雩。<AlignEnd Key=\"473\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"474\" RefId=\"魯僖公十三年十月\" Term=\"魯僖公十三年十月\"><\/AlignBegin>冬，公子友如齊。<AlignEnd Key=\"474\"><\/AlignEnd>\n<\/Content>"}},{"number":815,"docInfo":{"docId":"11129874","docFilename":"ChunQiu_00077","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十四年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"475\" RefId=\"魯僖公十四年正月\" Term=\"魯僖公十四年正月\"><\/AlignBegin>十有四年春，諸侯城緣陵。<AlignEnd Key=\"475\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"476\" RefId=\"魯僖公十四年六月\" Term=\"魯僖公十四年六月\"><\/AlignBegin>夏，六月，季姬及鄫子遇于防，使鄫子來朝。<AlignEnd Key=\"476\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"477\" RefId=\"魯僖公十四年八月\" Term=\"魯僖公十四年八月\"><\/AlignBegin>秋，八月，辛卯，沙鹿崩。<AlignEnd Key=\"477\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"478\" RefId=\"魯僖公十四年八月\" Term=\"魯僖公十四年八月\"><\/AlignBegin>狄侵鄭。<AlignEnd Key=\"478\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"479\" RefId=\"魯僖公十四年十月\" Term=\"魯僖公十四年十月\"><\/AlignBegin>冬，蔡侯肸卒。<AlignEnd Key=\"479\"><\/AlignEnd>\n<\/Content>"}},{"number":816,"docInfo":{"docId":"11129875","docFilename":"ChunQiu_00078","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十五年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"480\" RefId=\"魯僖公十五年正月\" Term=\"魯僖公十五年正月\"><\/AlignBegin>十有五年春，王正月，公如齊。<AlignEnd Key=\"480\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"481\" RefId=\"魯僖公十五年正月\" Term=\"魯僖公十五年正月\"><\/AlignBegin>楚人伐徐。<AlignEnd Key=\"481\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"482\" RefId=\"魯僖公十五年三月\" Term=\"魯僖公十五年三月\"><\/AlignBegin>三月，公會齊侯、宋公、陳侯、衛侯、鄭伯、許男、曹伯，盟于牡丘，遂次于匡。<AlignEnd Key=\"482\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"483\" RefId=\"魯僖公十五年三月\" Term=\"魯僖公十五年三月\"><\/AlignBegin>公孫敖帥師，及諸侯之大夫救徐。<AlignEnd Key=\"483\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"484\" RefId=\"魯僖公十五年五月\" Term=\"魯僖公十五年五月\"><\/AlignBegin>夏，五月，日有食之。<AlignEnd Key=\"484\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"485\" RefId=\"魯僖公十五年七月\" Term=\"魯僖公十五年七月\"><\/AlignBegin>秋，七月，齊師、曹師伐厲。<AlignEnd Key=\"485\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"486\" RefId=\"魯僖公十五年八月\" Term=\"魯僖公十五年八月\"><\/AlignBegin>八月，螽。<AlignEnd Key=\"486\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"487\" RefId=\"魯僖公十五年九月\" Term=\"魯僖公十五年九月\"><\/AlignBegin>九月，公至自會。<AlignEnd Key=\"487\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"488\" RefId=\"魯僖公十五年九月\" Term=\"魯僖公十五年九月\"><\/AlignBegin>季姬歸于鄫。<AlignEnd Key=\"488\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"489\" RefId=\"魯僖公十五年九月\" Term=\"魯僖公十五年九月\"><\/AlignBegin>己卯晦，震夷伯之廟。<AlignEnd Key=\"489\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"490\" RefId=\"魯僖公十五年十月\" Term=\"魯僖公十五年十月\"><\/AlignBegin>冬，宋人伐曹，楚人敗徐于婁林。<AlignEnd Key=\"490\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"491\" RefId=\"魯僖公十五年十一月\" Term=\"魯僖公十五年十一月\"><\/AlignBegin>十有一月，壬戌，晉侯及秦伯戰于韓，獲晉侯。<AlignEnd Key=\"491\"><\/AlignEnd>\n<\/Content>"}},{"number":817,"docInfo":{"docId":"11129876","docFilename":"ChunQiu_00079","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十六年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"492\" RefId=\"魯僖公十六年正月\" Term=\"魯僖公十六年正月\"><\/AlignBegin>十有六年春，王正月，戊申朔，隕石于宋五。是月，六鷁退飛，過宋都。<AlignEnd Key=\"492\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"493\" RefId=\"魯僖公十六年三月\" Term=\"魯僖公十六年三月\"><\/AlignBegin>三月，壬申，公子季友卒。<AlignEnd Key=\"493\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"494\" RefId=\"魯僖公十六年四月\" Term=\"魯僖公十六年四月\"><\/AlignBegin>夏，四月，丙申，鄫季姬卒。<AlignEnd Key=\"494\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"495\" RefId=\"魯僖公十六年七月\" Term=\"魯僖公十六年七月\"><\/AlignBegin>秋，七月，甲子，公孫茲卒。<AlignEnd Key=\"495\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"496\" RefId=\"魯僖公十六年十二月\" Term=\"魯僖公十六年十二月\"><\/AlignBegin>冬，十有二月，公會齊侯、宋公、陳侯、衛侯、鄭伯、許男、邢侯、曹伯于淮。<AlignEnd Key=\"496\"><\/AlignEnd>\n<\/Content>"}},{"number":818,"docInfo":{"docId":"11129877","docFilename":"ChunQiu_00080","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十七年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"497\" RefId=\"魯僖公十七年正月\" Term=\"魯僖公十七年正月\"><\/AlignBegin>十有七年春，齊人、徐人伐英氏。<AlignEnd Key=\"497\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"498\" RefId=\"魯僖公十七年四月\" Term=\"魯僖公十七年四月\"><\/AlignBegin>夏，滅項。<AlignEnd Key=\"498\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"499\" RefId=\"魯僖公十七年七月\" Term=\"魯僖公十七年七月\"><\/AlignBegin>秋，夫人姜氏會齊侯于卞。<AlignEnd Key=\"499\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"500\" RefId=\"魯僖公十七年九月\" Term=\"魯僖公十七年九月\"><\/AlignBegin>九月，公至自會。<AlignEnd Key=\"500\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"501\" RefId=\"魯僖公十七年十二月\" Term=\"魯僖公十七年十二月\"><\/AlignBegin>冬，十有二月，乙亥，齊侯小白卒。<AlignEnd Key=\"501\"><\/AlignEnd>\n<\/Content>"}},{"number":819,"docInfo":{"docId":"11129878","docFilename":"ChunQiu_00081","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十八年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"502\" RefId=\"魯僖公十八年正月\" Term=\"魯僖公十八年正月\"><\/AlignBegin>十有八年春，王正月，宋公、曹伯、衛人、邾人，伐齊。<AlignEnd Key=\"502\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"503\" RefId=\"魯僖公十八年四月\" Term=\"魯僖公十八年四月\"><\/AlignBegin>夏，師救齊。<AlignEnd Key=\"503\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"504\" RefId=\"魯僖公十八年五月\" Term=\"魯僖公十八年五月\"><\/AlignBegin>五月，戊寅，宋師及齊師戰于甗，齊師敗績。<AlignEnd Key=\"504\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"505\" RefId=\"魯僖公十八年五月\" Term=\"魯僖公十八年五月\"><\/AlignBegin>狄救齊。<AlignEnd Key=\"505\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"506\" RefId=\"魯僖公十八年八月\" Term=\"魯僖公十八年八月\"><\/AlignBegin>秋，八月，丁亥，葬齊桓公。<AlignEnd Key=\"506\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"507\" RefId=\"魯僖公十八年十月\" Term=\"魯僖公十八年十月\"><\/AlignBegin>冬，邢人、狄人伐衛。<AlignEnd Key=\"507\"><\/AlignEnd>\n<\/Content>"}},{"number":820,"docInfo":{"docId":"11129879","docFilename":"ChunQiu_00082","xmlFormatName":"ThdlContentXml","docXmlFormatSubname":"-","srcFilename":"_亦_銝\uf423\uefa6.xml","corpus":"春秋","corpusOrder":"1","placeInfo":[],"timeInfo":[],"docTitleXml":"<DocTitle>魯僖公十九年<\/DocTitle>","docTimeCreated":"2020-08-31 18:13:09","docContentXml":"<Content>\n<AlignBegin Type=\"Time\" Key=\"508\" RefId=\"魯僖公十九年三月\" Term=\"魯僖公十九年三月\"><\/AlignBegin>十有九年春，王三月，宋人執滕子嬰齊。<AlignEnd Key=\"508\"><\/AlignEnd>\n<AlignBegin Type=\"Time\" Key=\"509\" RefId=\"魯僖公十九年六月\" Term=\"魯僖公十九年六月\"><\/AlignBegi